# Allowed label categories (explicit allowlist)
ALLOWED_LABELS = frozenset(['cat', 'dog', 'bird', 'car', 'truck', 'bicycle', 'person', 'tree', 'building', 'other'])

# Rate limiting configuration
MAX_LABELS_PER_ANNOTATOR_PER_HOUR = 100
MAX_LABELS_PER_IMAGE = 10

# Database initialization
def init_db():
    conn = sqlite3.connect('labeling.db')
    c = conn.cursor()
    
    c.execute('''CREATE TABLE IF NOT EXISTS annotators
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  username TEXT UNIQUE NOT NULL,
                  api_key_hash TEXT NOT NULL,
                  reputation_score REAL DEFAULT 1.0,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
    
    c.execute('''CREATE TABLE IF NOT EXISTS images
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  image_hash TEXT UNIQUE NOT NULL,
                  image_data BLOB NOT NULL,
                  consensus_label TEXT,
                  label_count INTEGER DEFAULT 0,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
    
    c.execute('''CREATE TABLE IF NOT EXISTS labels
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  image_id INTEGER NOT NULL,
                  annotator_id INTEGER NOT NULL,
                  label TEXT NOT NULL,
                  confidence REAL DEFAULT 1.0,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  FOREIGN KEY (image_id) REFERENCES images(id),
                  FOREIGN KEY (annotator_id) REFERENCES annotators(id),
                  UNIQUE(image_id, annotator_id))''')
    
    c.execute('''CREATE TABLE IF NOT EXISTS rate_limits
                 (annotator_id INTEGER NOT NULL,
                  timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  FOREIGN KEY (annotator_id) REFERENCES annotators(id))''')
    
    c.execute('''CREATE INDEX IF NOT EXISTS idx_labels_image 
                 ON labels(image_id)''')
    c.execute('''CREATE INDEX IF NOT EXISTS idx_rate_limits 
                 ON rate_limits(annotator_id, timestamp)''')
    
    conn.commit()
    conn.close()

init_db()

def hash_api_key(api_key: str) -> str:
    """Securely hash API key"""
    return hashlib.pbkdf2_hmac('sha256', api_key.encode(), API_KEY_HASH_SALT.encode(), 100000).hex()

def verify_api_key(api_key: str, stored_hash: str) -> bool:
    """Verify API key against stored hash"""
    return hmac.compare_digest(hash_api_key(api_key), stored_hash)

def get_db():
    """Get database connection"""
    conn = sqlite3.connect('labeling.db')
    conn.row_factory = sqlite3.Row
    return conn

def authenticate_annotator(api_key: str) -> Optional[int]:
    """Authenticate annotator and return their ID"""
    if not api_key or len(api_key) < 32:
        return None
    
    conn = get_db()
    c = conn.cursor()
    c.execute('SELECT id, api_key_hash FROM annotators')
    
    for row in c.fetchall():
        if verify_api_key(api_key, row['api_key_hash']):
            conn.close()
            return row['id']
    
    conn.close()
    return None

def check_rate_limit(annotator_id: int) -> bool:
    """Check if annotator has exceeded rate limit"""
    conn = get_db()
    c = conn.cursor()
    
    one_hour_ago = datetime.now() - timedelta(hours=1)
    c.execute('''SELECT COUNT(*) as count FROM rate_limits 
                 WHERE annotator_id = ? AND timestamp > ?''',
              (annotator_id, one_hour_ago))
    
    count = c.fetchone()['count']
    conn.close()
    
    return count < MAX_LABELS_PER_ANNOTATOR_PER_HOUR

def record_rate_limit(annotator_id: int):
    """Record rate limit entry"""
    conn = get_db()
    c = conn.cursor()
    c.execute('INSERT INTO rate_limits (annotator_id) VALUES (?)', (annotator_id,))
    conn.commit()
    conn.close()

def validate_label(label: str) -> bool:
    """Validate label against allowlist"""
    return label in ALLOWED_LABELS

def validate_confidence(confidence: float) -> bool:
    """Validate confidence score"""
    return 0.0 <= confidence <= 1.0

def validate_image(image_data: bytes) -> bool:
    """Validate image data"""
    if len(image_data) > 10 * 1024 * 1024:  # 10MB max
        return False
    
    try:
        img = Image.open(io.BytesIO(image_data))
        # Verify it's a valid image
        img.verify()
        return True
    except:
        return False

def compute_image_hash(image_data: bytes) -> str:
    """Compute secure hash of image"""
    return hashlib.sha256(image_data).hexdigest()

def aggregate_labels(image_id: int) -> Optional[str]:
    """Aggregate labels using weighted majority voting based on annotator reputation"""
    conn = get_db()
    c = conn.cursor()
    
    c.execute('''SELECT l.label, l.confidence, a.reputation_score 
                 FROM labels l 
                 JOIN annotators a ON l.annotator_id = a.id 
                 WHERE l.image_id = ?''', (image_id,))
    
    labels = c.fetchall()
    conn.close()
    
    if not labels:
        return None
    
    # Weighted voting: weight = confidence * reputation_score
    weighted_votes = {}
    for row in labels:
        label = row['label']
        weight = row['confidence'] * row['reputation_score']
        weighted_votes[label] = weighted_votes.get(label, 0.0) + weight
    
    if not weighted_votes:
        return None
    
    # Return label with highest weighted vote
    consensus_label = max(weighted_votes.items(), key=lambda x: x[1])[0]
    return consensus_label

def update_annotator_reputation(annotator_id: int, is_correct: bool):
    """Update annotator reputation based on agreement with consensus"""
    conn = get_db()
    c = conn.cursor()
    
    c.execute('SELECT reputation_score FROM annotators WHERE id = ?', (annotator_id,))
    current_score = c.fetchone()['reputation_score']
    
    # Simple reputation update: increase if correct, decrease if incorrect
    if is_correct:
        new_score = min(2.0, current_score * 1.05)
    else:
        new_score = max(0.1, current_score * 0.95)
    
    c.execute('UPDATE annotators SET reputation_score = ? WHERE id = ?',
              (new_score, annotator_id))
    conn.commit()
    conn.close()

@app.route('/api/v1/register', methods=['POST'])
def register_annotator():
    """Register new annotator"""
    try:
        data = request.get_json()
        
        if not data or 'username' not in data:
            return jsonify({'error': 'Invalid request'}), 400
        
        username = str(data['username']).strip()
        
        # Validate username
        if not username or len(username) < 3 or len(username) > 50:
            return jsonify({'error': 'Invalid username'}), 400
        
        if not username.isalnum():
            return jsonify({'error': 'Username must be alphanumeric'}), 400
        
        # Generate secure API key
        api_key = secrets.token_urlsafe(32)
        api_key_hash = hash_api_key(api_key)
        
        conn = get_db()
        c = conn.cursor()
        
        try:
            c.execute('INSERT INTO annotators (username, api_key_hash) VALUES (?, ?)',
                     (username, api_key_hash))
            conn.commit()
            annotator_id = c.lastrowid
        except sqlite3.IntegrityError:
            conn.close()
            return jsonify({'error': 'Username already exists'}), 409
        
        conn.close()
        
        return jsonify({
            'annotator_id': annotator_id,
            'api_key': api_key,
            'message': 'Store this API key securely. It will not be shown again.'
        }), 201
        
    except Exception as e:
        return jsonify({'error': 'Registration failed'}), 500

@app.route('/api/v1/images', methods=['POST'])
def upload_image():
    """Upload image for labeling"""
    api_key = request.headers.get('X-API-Key')
    annotator_id = authenticate_annotator(api_key)
    
    if not annotator_id:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        data = request.get_json()
        
        if not data or 'image' not in data:
            return jsonify({'error': 'Invalid request'}), 400
        
        # Decode base64 image
        try:
            image_data = base64.b64decode(data['image'])
        except:
            return jsonify({'error': 'Invalid image encoding'}), 400
        
        # Validate image
        if not validate_image(image_data):
            return jsonify({'error': 'Invalid image'}), 400
        
        image_hash = compute_image_hash(image_data)
        
        conn = get_db()
        c = conn.cursor()
        
        # Check if image already exists
        c.execute('SELECT id FROM images WHERE image_hash = ?', (image_hash,))
        existing = c.fetchone()
        
        if existing:
            conn.close()
            return jsonify({'image_id': existing['id'], 'message': 'Image already exists'}), 200
        
        # Store image
        c.execute('INSERT INTO images (image_hash, image_data) VALUES (?, ?)',
                 (image_hash, image_data))
        conn.commit()
        image_id = c.lastrowid
        conn.close()
        
        return jsonify({'image_id': image_id}), 201
        
    except Exception as e:
        return jsonify({'error': 'Upload failed'}), 500

@app.route('/api/v1/labels', methods=['POST'])
def submit_label():
    """Submit label for an image"""
    api_key = request.headers.get('X-API-Key')
    annotator_id = authenticate_annotator(api_key)
    
    if not annotator_id:
        return jsonify({'error': 'Unauthorized'}), 401
    
    # Check rate limit
    if not check_rate_limit(annotator_id):
        return jsonify({'error': 'Rate limit exceeded'}), 429
    
    try:
        data = request.get_json()
        
        if not data or 'image_id' not in data or 'label' not in data:
            return jsonify({'error': 'Invalid request'}), 400
        
        image_id = int(data['image_id'])
        label = str(data['label']).strip().lower()
        confidence = float(data.get('confidence', 1.0))
        
        # Validate label
        if not validate_label(label):
            return jsonify({'error': 'Invalid label. Must be one of: ' + ', '.join(ALLOWED_LABELS)}), 400
        
        # Validate confidence
        if not validate_confidence(confidence):
            return jsonify({'error': 'Invalid confidence. Must be between 0.0 and 1.0'}), 400
        
        conn = get_db()
        c = conn.cursor()
        
        # Verify image exists
        c.execute('SELECT id, label_count FROM images WHERE id = ?', (image_id,))
        image = c.fetchone()
        
        if not image:
            conn.close()
            return jsonify({'error': 'Image not found'}), 404
        
        # Check max labels per image
        if image['label_count'] >= MAX_LABELS_PER_IMAGE:
            conn.close()
            return jsonify({'error': 'Maximum labels reached for this image'}), 400
        
        # Insert label
        try:
            c.execute('''INSERT INTO labels (image_id, annotator_id, label, confidence) 
                        VALUES (?, ?, ?, ?)''',
                     (image_id, annotator_id, label, confidence))
            conn.commit()
        except sqlite3.IntegrityError:
            conn.close()
            return jsonify({'error': 'You have already labeled this image'}), 409
        
        # Update label count
        c.execute('UPDATE images SET label_count = label_count + 1 WHERE id = ?', (image_id,))
        conn.commit()
        
        # Record rate limit
        record_rate_limit(annotator_id)
        
        # Aggregate labels
        consensus_label = aggregate_labels(image_id)
        
        if consensus_label:
            c.execute('UPDATE images SET consensus_label = ? WHERE id = ?',
                     (consensus_label, image_id))
            conn.commit()
        
        conn.close()
        
        return jsonify({
            'message': 'Label submitted successfully',
            'consensus_label': consensus_label
        }), 201
        
    except ValueError:
        return jsonify({'error': 'Invalid data types'}), 400
    except Exception as e:
        return jsonify({'error': 'Submission failed'}), 500

