@app.route('/api/v1/training-data', methods=['GET'])
def get_training_data():
    """Get labeled data for training (admin only)"""
    api_key = request.headers.get('X-API-Key')
    annotator_id = authenticate_annotator(api_key)
    
    if not annotator_id:
        return jsonify({'error': 'Unauthorized'}), 401
    
    try:
        conn = get_db()
        c = conn.cursor()
        
        # Only return images with consensus labels
        c.execute('''SELECT id, image_data, consensus_label 
                    FROM images 
                    WHERE consensus_label IS NOT NULL''')
        
        training_data = []
        for row in c.fetchall():
            training_data.append({
                'image_id': row['id'],
                'image': base64.b64encode(row['image_data']).decode('utf-8'),
                'label': row['consensus_label']
            })
        
        conn.close()
        
        return jsonify({
            'count': len(training_data),
            'data': training_data
        }), 200
        
    except Exception as e:
        return jsonify({'error': 'Retrieval failed'}), 500

